import React, { useState } from "react";
import { uploadFile, fetchGoogleSheet } from "../services/api";

function Upload({ setUrls }) {
  const [file, setFile] = useState(null);
  const [sheetUrl, setSheetUrl] = useState("");

  const handleUpload = async (e) => {
    e.preventDefault(); // ✅ prevent reload

    if (!file) {
      alert("Please select a file");
      return;
    }

    try {
      const res = await uploadFile(file);
      setUrls(res.data.urls);
    } catch (err) {
      console.error(err);
    }
  };

  const handleGoogleSheet = async (e) => {
    e.preventDefault(); // ✅ prevent reload

    if (!sheetUrl) {
      alert("Enter URL first");
      return;
    }

    try {
      const res = await fetchGoogleSheet(sheetUrl);
      setUrls(res.data.urls);
    } catch (err) {
      console.error(err.response?.data || err.message);
    }
  };

  return (
    <div>
      {/* ✅ NO FORM TAG (important) */}

      <input
        type="file"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <button type="button" onClick={handleUpload}>
        Upload File
      </button>

      <br /><br />

      <input
        type="text"
        placeholder="Paste Google Sheet URL"
        value={sheetUrl}
        onChange={(e) => setSheetUrl(e.target.value)}
      />

      <button type="button" onClick={handleGoogleSheet}>
        Load Sheet
      </button>
    </div>
  );
}

export default Upload;
